import React, { useState, useEffect, useContext } from 'react';
import { Link } from 'react-router-dom';
import { Search, Filter, TrendingUp, Calendar, Star, Trash2, Eye, BarChart3, User, Film } from 'lucide-react';

// Mock context and services for demo
const AuthContext = React.createContext({ user: { name: 'John Doe', id: 1 } });
const LoadingSpinner = () => <div className="loading-spinner">Loading...</div>;

const getMyRatings = async ({ page, limit }) => {
  // Mock data
  return {
    ratings: Array.from({ length: 20 }, (_, i) => ({
      movie_id: i + 1,
      movie_title: ['The Dark Knight', 'Inception', 'Pulp Fiction', 'The Shawshank Redemption', 'Fight Club'][i % 5],
      movie_year: 2000 + (i % 24),
      rating: 3 + Math.random() * 2,
      timestamp: new Date(2024, 0, 1 + i).toISOString(),
      review: i % 3 === 0 ? 'Amazing movie with incredible cinematography and storytelling!' : null,
      poster_url: `https://picsum.photos/300/450?random=${i}`
    }))
  };
};

const deleteRating = async (movieId) => {
  return new Promise(resolve => setTimeout(resolve, 1000));
};

const MyRatingsPage = () => {
  const { user } = useContext(AuthContext);
  const [ratings, setRatings] = useState([]);
  const [filteredRatings, setFilteredRatings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [sortBy, setSortBy] = useState('newest');
  const [filterRating, setFilterRating] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [deleteLoading, setDeleteLoading] = useState(null);
  const [viewMode, setViewMode] = useState('grid');

  useEffect(() => {
    if (user) {
      fetchRatings(true);
    }
  }, [user]);

  useEffect(() => {
    applyFiltersAndSort();
  }, [ratings, sortBy, filterRating, searchQuery]);

  const fetchRatings = async (reset = false) => {
    setLoading(true);
    setError(null);

    try {
      const currentPage = reset ? 1 : page;
      const data = await getMyRatings({
        page: currentPage,
        limit: 20
      });

      if (reset) {
        setRatings(data.ratings);
        setPage(2);
      } else {
        setRatings(prev => [...prev, ...data.ratings]);
        setPage(prev => prev + 1);
      }

      setHasMore(data.ratings.length === 20);
    } catch (error) {
      console.error('Error fetching ratings:', error);
      setError('Failed to load your ratings. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const applyFiltersAndSort = () => {
    let filtered = [...ratings];

    if (searchQuery.trim()) {
      filtered = filtered.filter(rating =>
        rating.movie_title.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }

    if (filterRating !== 'all') {
      const ratingValue = parseInt(filterRating);
      filtered = filtered.filter(rating => Math.floor(rating.rating) === ratingValue);
    }

    filtered.sort((a, b) => {
      switch (sortBy) {
        case 'newest':
          return new Date(b.timestamp) - new Date(a.timestamp);
        case 'oldest':
          return new Date(a.timestamp) - new Date(b.timestamp);
        case 'highest':
          return b.rating - a.rating;
        case 'lowest':
          return a.rating - b.rating;
        case 'title':
          return a.movie_title.localeCompare(b.movie_title);
        case 'year':
          return b.movie_year - a.movie_year;
        default:
          return 0;
      }
    });

    setFilteredRatings(filtered);
  };

  const handleDeleteRating = async (movieId, movieTitle) => {
    if (!window.confirm(`Are you sure you want to delete your rating for "${movieTitle}"?`)) {
      return;
    }

    setDeleteLoading(movieId);

    try {
      await deleteRating(movieId);
      setRatings(prev => prev.filter(rating => rating.movie_id !== movieId));
    } catch (error) {
      console.error('Error deleting rating:', error);
    } finally {
      setDeleteLoading(null);
    }
  };

  const renderStars = (rating) => {
    const fullStars = Math.floor(rating);
    const hasHalfStar = rating % 1 >= 0.5;
    const emptyStars = 5 - fullStars - (hasHalfStar ? 1 : 0);

    return (
      <div className="flex items-center gap-1">
        {[...Array(fullStars)].map((_, i) => (
          <Star key={i} className="w-4 h-4 fill-yellow-400 text-yellow-400" />
        ))}
        {hasHalfStar && <Star className="w-4 h-4 fill-yellow-400/50 text-yellow-400" />}
        {[...Array(emptyStars)].map((_, i) => (
          <Star key={i} className="w-4 h-4 text-gray-300" />
        ))}
      </div>
    );
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const getRatingColor = (rating) => {
    if (rating >= 4.5) return '#10b981';
    if (rating >= 3.5) return '#84cc16';
    if (rating >= 2.5) return '#f59e0b';
    if (rating >= 1.5) return '#f97316';
    return '#ef4444';
  };

  const getStatistics = () => {
    if (ratings.length === 0) return null;

    const totalRatings = ratings.length;
    const avgRating = ratings.reduce((sum, r) => sum + r.rating, 0) / totalRatings;
    const ratingCounts = ratings.reduce((acc, r) => {
      const star = Math.floor(r.rating);
      acc[star] = (acc[star] || 0) + 1;
      return acc;
    }, {});

    return { totalRatings, avgRating, ratingCounts };
  };

  if (!user) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-indigo-50 via-purple-50 to-pink-50 flex items-center justify-center p-4">
        <div className="bg-white/80 backdrop-blur-lg rounded-3xl shadow-2xl p-12 text-center max-w-md border border-white/20">
          <User className="w-20 h-20 mx-auto mb-6 text-indigo-600" />
          <h2 className="text-3xl font-bold text-gray-900 mb-4">Welcome Back!</h2>
          <p className="text-gray-600 mb-8">Sign in to view your movie ratings and discover your viewing patterns.</p>
          <Link 
            to="/login" 
            className="inline-flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-purple-600 text-white px-8 py-4 rounded-2xl font-semibold hover:from-indigo-700 hover:to-purple-700 transform hover:scale-105 transition-all duration-200 shadow-lg hover:shadow-xl"
          >
            Sign In
          </Link>
        </div>
      </div>
    );
  }

  if (loading && ratings.length === 0) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-indigo-50 via-purple-50 to-pink-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-indigo-600 mx-auto mb-4"></div>
          <p className="text-lg text-gray-600">Loading your ratings...</p>
        </div>
      </div>
    );
  }

  const stats = getStatistics();

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-50 via-purple-50 to-pink-50">
      <div className="max-w-7xl mx-auto px-4 py-8">
        {/* Header */}
        <div className="text-center mb-12">
          <div className="inline-flex items-center gap-3 mb-4">
            <div className="p-3 bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl">
              <BarChart3 className="w-8 h-8 text-white" />
            </div>
            <h1 className="text-5xl font-bold bg-gradient-to-r from-indigo-600 via-purple-600 to-pink-600 bg-clip-text text-transparent">
              My Movie Ratings
            </h1>
          </div>

          {stats && (
            <div className="flex items-center justify-center gap-8 mt-8">
              <div className="bg-white/70 backdrop-blur-lg rounded-2xl px-6 py-4 border border-white/20 shadow-lg">
                <div className="text-3xl font-bold text-indigo-600">{stats.totalRatings}</div>
                <div className="text-sm text-gray-600 font-medium">Movies Rated</div>
              </div>
              <div className="bg-white/70 backdrop-blur-lg rounded-2xl px-6 py-4 border border-white/20 shadow-lg">
                <div className="text-3xl font-bold text-purple-600">{stats.avgRating.toFixed(1)}</div>
                <div className="text-sm text-gray-600 font-medium">Average Rating</div>
              </div>
            </div>
          )}
        </div>

        {error && (
          <div className="bg-red-50 border border-red-200 rounded-2xl p-6 mb-8">
            <div className="flex items-center gap-3 mb-4">
              <div className="w-10 h-10 bg-red-100 rounded-full flex items-center justify-center">
                <span className="text-red-600">⚠</span>
              </div>
              <p className="text-red-800 font-medium">{error}</p>
            </div>
            <button 
              onClick={() => fetchRatings(true)}
              className="bg-red-600 text-white px-6 py-2 rounded-xl hover:bg-red-700 transition-colors"
            >
              Try Again
            </button>
          </div>
        )}

        {ratings.length > 0 ? (
          <>
            {/* Controls */}
            <div className="bg-white/80 backdrop-blur-lg rounded-3xl shadow-xl p-8 mb-8 border border-white/20">
              {/* Search Bar */}
              <div className="relative mb-8">
                <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
                <input
                  type="text"
                  placeholder="Search your rated movies..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-100 focus:border-indigo-500 transition-all text-lg"
                />
              </div>

              {/* Filters */}
              <div className="flex flex-wrap items-center justify-between gap-6">
                <div className="flex items-center gap-6">
                  <div className="flex items-center gap-3">
                    <TrendingUp className="w-5 h-5 text-gray-500" />
                    <select
                      value={sortBy}
                      onChange={(e) => setSortBy(e.target.value)}
                      className="bg-white border border-gray-200 rounded-xl px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-100 focus:border-indigo-500"
                    >
                      <option value="newest">Newest First</option>
                      <option value="oldest">Oldest First</option>
                      <option value="highest">Highest Rated</option>
                      <option value="lowest">Lowest Rated</option>
                      <option value="title">Movie Title</option>
                      <option value="year">Release Year</option>
                    </select>
                  </div>

                  <div className="flex items-center gap-3">
                    <Filter className="w-5 h-5 text-gray-500" />
                    <select
                      value={filterRating}
                      onChange={(e) => setFilterRating(e.target.value)}
                      className="bg-white border border-gray-200 rounded-xl px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-100 focus:border-indigo-500"
                    >
                      <option value="all">All Ratings</option>
                      <option value="5">5 Stars</option>
                      <option value="4">4 Stars</option>
                      <option value="3">3 Stars</option>
                      <option value="2">2 Stars</option>
                      <option value="1">1 Star</option>
                    </select>
                  </div>
                </div>

                <div className="flex items-center gap-2 bg-gray-100 rounded-xl p-1">
                  <button
                    onClick={() => setViewMode('grid')}
                    className={`p-2 rounded-lg transition-all ${
                      viewMode === 'grid' 
                        ? 'bg-white shadow-sm text-indigo-600' 
                        : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    <div className="grid grid-cols-2 gap-1 w-4 h-4">
                      <div className="bg-current rounded-sm"></div>
                      <div className="bg-current rounded-sm"></div>
                      <div className="bg-current rounded-sm"></div>
                      <div className="bg-current rounded-sm"></div>
                    </div>
                  </button>
                  <button
                    onClick={() => setViewMode('list')}
                    className={`p-2 rounded-lg transition-all ${
                      viewMode === 'list' 
                        ? 'bg-white shadow-sm text-indigo-600' 
                        : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    <div className="space-y-1 w-4 h-4">
                      <div className="h-1 bg-current rounded"></div>
                      <div className="h-1 bg-current rounded"></div>
                      <div className="h-1 bg-current rounded"></div>
                    </div>
                  </button>
                </div>
              </div>
            </div>

            {/* Statistics */}
            {stats && (
              <div className="bg-white/80 backdrop-blur-lg rounded-3xl shadow-xl p-8 mb-8 border border-white/20">
                <h3 className="text-2xl font-bold text-gray-800 mb-6 flex items-center gap-3">
                  <BarChart3 className="w-6 h-6 text-indigo-600" />
                  Rating Distribution
                </h3>
                <div className="space-y-4 max-w-2xl">
                  {[5, 4, 3, 2, 1].map(star => (
                    <div key={star} className="flex items-center gap-4">
                      <div className="flex items-center gap-2 w-16">
                        <span className="font-semibold text-gray-700">{star}</span>
                        <Star className="w-4 h-4 fill-yellow-400 text-yellow-400" />
                      </div>
                      <div className="flex-1 h-3 bg-gray-200 rounded-full overflow-hidden">
                        <div
                          className="h-full rounded-full transition-all duration-1000"
                          style={{
                            width: `${stats.ratingCounts[star] ? (stats.ratingCounts[star] / stats.totalRatings) * 100 : 0}%`,
                            backgroundColor: getRatingColor(star)
                          }}
                        ></div>
                      </div>
                      <span className="font-semibold text-gray-600 w-8 text-right">
                        {stats.ratingCounts[star] || 0}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Ratings Grid/List */}
            <div className={`mb-8 ${
              viewMode === 'grid' 
                ? 'grid grid-cols-1 lg:grid-cols-2 gap-6' 
                : 'space-y-4'
            }`}>
              {filteredRatings.length > 0 ? (
                filteredRatings.map((rating) => (
                  <div 
                    key={rating.movie_id} 
                    className="bg-white/80 backdrop-blur-lg rounded-2xl shadow-lg hover:shadow-xl border border-white/20 overflow-hidden group transition-all duration-300 hover:-translate-y-1"
                  >
                    <div className={`p-6 ${viewMode === 'list' ? 'flex items-center gap-6' : ''}`}>
                      {/* Movie Poster */}
                      <div className={`flex-shrink-0 ${viewMode === 'list' ? 'w-20 h-28' : 'w-full h-64 mb-4'}`}>
                        <img
                          src={rating.poster_url || '/api/placeholder/300/450'}
                          alt={rating.movie_title}
                          className="w-full h-full object-cover rounded-xl group-hover:scale-105 transition-transform duration-300"
                        />
                      </div>

                      {/* Content */}
                      <div className="flex-1">
                        <div className="flex items-start justify-between mb-3">
                          <div>
                            <Link 
                              to={`/movies/${rating.movie_id}`}
                              className="text-xl font-bold text-gray-800 hover:text-indigo-600 transition-colors"
                            >
                              {rating.movie_title}
                            </Link>
                            <p className="text-gray-500 font-medium">({rating.movie_year})</p>
                          </div>
                          <div className="text-right">
                            {renderStars(rating.rating)}
                            <div 
                              className="text-lg font-bold mt-1"
                              style={{ color: getRatingColor(rating.rating) }}
                            >
                              {rating.rating.toFixed(1)}/5
                            </div>
                          </div>
                        </div>

                        <div className="flex items-center gap-2 text-sm text-gray-500 mb-3">
                          <Calendar className="w-4 h-4" />
                          Rated on {formatDate(rating.timestamp)}
                        </div>

                        {rating.review && (
                          <div className="bg-indigo-50 rounded-xl p-4 mb-4">
                            <p className="text-gray-700 italic">"{rating.review}"</p>
                          </div>
                        )}

                        <div className="flex items-center gap-3">
                          <Link
                            to={`/movies/${rating.movie_id}`}
                            className="inline-flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-purple-600 text-white px-4 py-2 rounded-xl font-medium hover:from-indigo-700 hover:to-purple-700 transition-all transform hover:scale-105"
                          >
                            <Eye className="w-4 h-4" />
                            View Movie
                          </Link>
                          <button
                            onClick={() => handleDeleteRating(rating.movie_id, rating.movie_title)}
                            disabled={deleteLoading === rating.movie_id}
                            className="inline-flex items-center gap-2 bg-red-100 text-red-600 px-4 py-2 rounded-xl font-medium hover:bg-red-200 transition-colors disabled:opacity-50"
                          >
                            <Trash2 className="w-4 h-4" />
                            {deleteLoading === rating.movie_id ? 'Deleting...' : 'Delete'}
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="col-span-full bg-white/80 backdrop-blur-lg rounded-3xl shadow-xl p-12 text-center border border-white/20">
                  <Film className="w-16 h-16 mx-auto mb-4 text-gray-400" />
                  <h3 className="text-2xl font-bold text-gray-800 mb-2">No movies found</h3>
                  <p className="text-gray-600">
                    {searchQuery 
                      ? `No movies match your search for "${searchQuery}"` 
                      : filterRating !== 'all' 
                        ? `No movies with ${filterRating} star rating` 
                        : 'No ratings to show'
                    }
                  </p>
                </div>
              )}
            </div>

            {/* Load More */}
            {hasMore && !searchQuery && filterRating === 'all' && (
              <div className="text-center mb-8">
                <button
                  onClick={() => fetchRatings(false)}
                  disabled={loading}
                  className="bg-gradient-to-r from-indigo-600 to-purple-600 text-white px-8 py-4 rounded-2xl font-semibold hover:from-indigo-700 hover:to-purple-700 transition-all transform hover:scale-105 shadow-lg hover:shadow-xl disabled:opacity-50"
                >
                  {loading ? 'Loading...' : 'Load More Ratings'}
                </button>
              </div>
            )}

            {/* Results Summary */}
            {filteredRatings.length !== ratings.length && (
              <div className="text-center text-gray-500 text-lg">
                Showing {filteredRatings.length} of {ratings.length} ratings
              </div>
            )}
          </>
        ) : (
          <div className="bg-white/80 backdrop-blur-lg rounded-3xl shadow-xl p-16 text-center border border-white/20">
            <Film className="w-24 h-24 mx-auto mb-8 text-indigo-300" />
            <h3 className="text-3xl font-bold text-gray-800 mb-4">No movies rated yet</h3>
            <p className="text-xl text-gray-600 mb-12 max-w-md mx-auto">
              Start rating movies to build your profile and discover personalized recommendations!
            </p>
            <div className="flex items-center justify-center gap-6">
              <Link 
                to="/movies" 
                className="inline-flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-purple-600 text-white px-8 py-4 rounded-2xl font-semibold hover:from-indigo-700 hover:to-purple-700 transition-all transform hover:scale-105 shadow-lg hover:shadow-xl"
              >
                Browse Movies
              </Link>
              <Link 
                to="/recommendations" 
                className="inline-flex items-center gap-2 bg-white text-indigo-600 px-8 py-4 rounded-2xl font-semibold hover:bg-indigo-50 transition-all transform hover:scale-105 shadow-lg border border-indigo-200"
              >
                View Popular Movies
              </Link>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default MyRatingsPage;
